const FIRST = ['James','Mary','Robert','Patricia','John','Jennifer','Michael','Linda','William','Barbara','David','Susan','Richard','Jessica','Joseph','Sarah','Thomas','Karen','Charles','Lisa','Christopher','Nancy','Daniel','Betty','Matthew','Margaret','Anthony','Sandra','Mark','Ashley','Donald','Dorothy','Steven','Kimberly','Paul','Emily','Andrew','Donna','Joshua','Michelle','Kenneth','Carol','Kevin','Amanda','Brian','Melissa','Timothy','Deborah','Ronald','Stephanie'];
const LAST = ['Smith','Johnson','Williams','Brown','Jones','Garcia','Miller','Davis','Martinez','Hernandez','Lopez','Gonzalez','Wilson','Anderson','Thomas','Taylor','Moore','Jackson','Martin','Lee','Perez','Thompson','White','Harris','Sanchez','Clark','Lewis','Robinson','Walker','Young','Allen','King','Wright','Scott','Torres','Hill','Flores','Green','Adams','Nelson','Baker','Hall','Rivera','Campbell','Mitchell','Carter','Roberts'];
const DOMAINS = ['gmail.com','yahoo.com','outlook.com','icloud.com','proton.me','company.com','example.org'];
const STREETS = ['Main St','Oak Ave','Maple Dr','Cedar Ln','Pine Rd','Elm St','Park Blvd','Lake View Dr','Summit Way','Riverside Rd'];
const CITIES = ['Springfield','Riverside','Fairview','Madison','Georgetown','Franklin','Bristol','Salem','Greenfield','Oakland'];
const STATES = ['CA','TX','FL','NY','PA','IL','OH','GA','NC','MI'];

function rand(arr) { return arr[Math.floor(Math.random() * arr.length)]; }
function phone() {
  const a = Math.floor(Math.random()*800)+200;
  const b = Math.floor(Math.random()*900)+100;
  const c = Math.floor(Math.random()*9000)+1000;
  return `(${a}) ${b}-${c}`;
}

const count = Math.max(1, Math.min(50, Number(options.count ?? 5)));
const fmt = options.format ?? 'text';
const people = [];
for (let i = 0; i < count; i++) {
  const first = rand(FIRST);
  const last = rand(LAST);
  const email = `${first.toLowerCase()}.${last.toLowerCase()}${Math.floor(Math.random()*99)+1}@${rand(DOMAINS)}`;
  const address = `${Math.floor(Math.random()*9000)+100} ${rand(STREETS)}, ${rand(CITIES)}, ${rand(STATES)} ${String(Math.floor(Math.random()*90000)+10000)}`;
  people.push({ name: `${first} ${last}`, email, phone: phone(), address });
}

let output;
if (fmt === 'json') {
  output = JSON.stringify(people, null, 2);
} else if (fmt === 'csv') {
  const hdr = 'Name,Email,Phone,Address';
  const rows = people.map(p => `"${p.name}","${p.email}","${p.phone}","${p.address}"`);
  output = [hdr, ...rows].join('\n');
} else {
  output = people.map((p, i) =>
    `#${i+1}\n  Name:    ${p.name}\n  Email:   ${p.email}\n  Phone:   ${p.phone}\n  Address: ${p.address}`
  ).join('\n\n');
}
return { output, outputLanguage: fmt === 'json' ? 'json' : 'text' };
